import { useRef, useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const EVENTS = [
  {
    id: '1',
    icon: 'ri-checkbox-circle-fill',
    color: '#22c55e',
    bg: 'rgba(34,197,94,0.10)',
    ring: 'rgba(34,197,94,0.18)',
    action: 'Has terminado',
    item: 'Cyberpunk 2077',
    detail: 'Videojuego · 100 / 100 logros desbloqueados',
    time: 'hace 2 días',
  },
  {
    id: '2',
    icon: 'ri-star-fill',
    color: '#f59e0b',
    bg: 'rgba(245,158,11,0.10)',
    ring: 'rgba(245,158,11,0.18)',
    action: 'Has puntuado',
    item: 'Interstellar',
    detail: 'Película · 10 / 10',
    time: 'hace 3 días',
  },
  {
    id: '3',
    icon: 'ri-add-circle-fill',
    color: '#3b82f6',
    bg: 'rgba(59,130,246,0.10)',
    ring: 'rgba(59,130,246,0.18)',
    action: 'Has añadido',
    item: 'Dune: Parte Dos',
    detail: 'Película · 2024 · Añadido a pendientes',
    time: 'hace 5 días',
  },
  {
    id: '4',
    icon: 'ri-play-circle-fill',
    color: '#f97316',
    bg: 'rgba(249,115,22,0.10)',
    ring: 'rgba(249,115,22,0.18)',
    action: 'Has retomado',
    item: 'Breaking Bad',
    detail: 'Serie · Temporada 6 · Episodio 10',
    time: 'hace 1 semana',
  },
  {
    id: '5',
    icon: 'ri-quill-pen-fill',
    color: '#8b5cf6',
    bg: 'rgba(139,92,246,0.10)',
    ring: 'rgba(139,92,246,0.18)',
    action: 'Has reseñado',
    item: 'The Witcher 3',
    detail: '"Una experiencia única. La mejor narrativa en videojuegos."',
    time: 'hace 2 semanas',
  },
] as const;

export default function ActivitySection() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.1 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="py-24 px-4 md:px-6 bg-[var(--surface)] dark:bg-[var(--bg)]">
      <div className="max-w-screen-xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_520px] gap-16 items-start">

          {/* Left — sticky heading */}
          <div
            className="lg:sticky lg:top-24 transition-all duration-700"
            style={{ opacity: visible ? 1 : 0, transform: visible ? 'none' : 'translateY(20px)' }}
          >
            <p className="mb-3 text-[11px] font-bold uppercase tracking-[0.14em] text-[var(--brand-accent)] dark:text-blue-400">
              Tu actividad
            </p>
            <h2
              className="mb-5 text-3xl font-black leading-[1.1] tracking-tight text-zinc-900 dark:text-white md:text-4xl"
              style={{ fontFamily: "'Space Grotesk', sans-serif" }}
            >
              Tu historia se
              <br />construye sola.
            </h2>
            <p className="mb-8 max-w-sm text-base leading-relaxed text-zinc-500 dark:text-zinc-400">
              Cada título que completas, cada puntuación que dejas,
              cada cosa que añades — queda guardada para siempre.
            </p>
            <Link
              to="/auth"
              className="inline-flex cursor-pointer items-center gap-2 rounded-xl bg-zinc-900 dark:bg-white px-5 py-2.5 text-sm font-bold text-white dark:text-zinc-900 transition-opacity hover:opacity-85"
            >
              Empieza a registrar
              <i className="ri-arrow-right-line" />
            </Link>
          </div>

          {/* Right — timeline */}
          <div ref={ref}>
            <div className="relative">
              {/* Vertical line */}
              <div className="absolute left-[19px] top-5 bottom-5 w-px bg-zinc-200 dark:bg-zinc-800" />

              <div className="flex flex-col gap-0">
                {EVENTS.map((ev, i) => (
                  <div
                    key={ev.id}
                    className="relative flex gap-5 pb-7 last:pb-0 transition-all duration-700"
                    style={{
                      opacity: visible ? 1 : 0,
                      transform: visible ? 'none' : 'translateX(16px)',
                      transitionDelay: `${i * 80}ms`,
                    }}
                  >
                    {/* Icon node */}
                    <div
                      className="relative z-10 mt-0.5 flex h-[38px] w-[38px] flex-shrink-0 items-center justify-center rounded-full"
                      style={{
                        background: ev.bg,
                        border: `1.5px solid ${ev.ring}`,
                      }}
                    >
                      <i className={`${ev.icon} text-[14px]`} style={{ color: ev.color }} />
                    </div>

                    {/* Content */}
                    <div className="min-w-0 flex-1 rounded-xl border border-[var(--border)] bg-[var(--surface)] px-4 py-3.5 shadow-[var(--shadow-sm)]">
                      <div className="flex items-start justify-between gap-2 mb-1">
                        <p className="text-[13px] leading-snug text-zinc-900 dark:text-white">
                          <span className="font-semibold">{ev.action}</span>{' '}
                          <span className="font-bold" style={{ color: ev.color }}>
                            {ev.item}
                          </span>
                        </p>
                        <span className="flex-shrink-0 text-[11px] text-zinc-400 dark:text-zinc-600">
                          {ev.time}
                        </span>
                      </div>
                      <p className="text-[12px] leading-relaxed text-zinc-500 dark:text-zinc-500">
                        {ev.detail}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

        </div>
      </div>
    </section>
  );
}
