import { useRef, useState, useEffect } from 'react';

const BEFORE = [
  { app: 'Letterboxd', for: 'películas', icon: 'ri-film-line', color: '#f97316' },
  { app: 'Backloggd', for: 'videojuegos', icon: 'ri-gamepad-line', color: '#3b82f6' },
  { app: 'Goodreads', for: 'libros', icon: 'ri-book-open-line', color: '#fbbf24' },
  { app: 'Trakt', for: 'series', icon: 'ri-tv-2-line', color: '#8b5cf6' },
  { app: '¿Y los conciertos?', for: '', icon: 'ri-music-2-line', color: '#64748b' },
];

const AFTER = [
  { label: 'Videojuegos',  icon: 'ri-gamepad-line',    color: '#3b82f6' },
  { label: 'Películas',    icon: 'ri-film-line',        color: '#f97316' },
  { label: 'Series',       icon: 'ri-tv-2-line',        color: '#8b5cf6' },
  { label: 'Libros',       icon: 'ri-book-open-line',   color: '#fbbf24' },
  { label: 'Conciertos',   icon: 'ri-music-2-line',     color: '#ec4899' },
];

const FEATURES = [
  {
    icon: 'ri-stack-line',
    color: '#2563eb',
    bg: 'rgba(37,99,235,0.1)',
    title: 'Todo centralizado',
    desc: 'Un solo tracker para cualquier tipo de contenido, con el mismo flujo para todos.',
  },
  {
    icon: 'ri-history-line',
    color: '#f97316',
    bg: 'rgba(249,115,22,0.1)',
    title: 'Tu historial siempre ahí',
    desc: 'Ve qué has completado, qué tienes en progreso y qué te queda pendiente.',
  },
  {
    icon: 'ri-compass-3-line',
    color: '#22c55e',
    bg: 'rgba(34,197,94,0.1)',
    title: 'Descubre lo siguiente',
    desc: 'Explora el catálogo desde lo que ya te gusta. Sin recomendaciones algorítmicas.',
  },
];

export default function WhySection() {
  const sectionRef = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = sectionRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.15 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <section className="py-24 px-4 md:px-6 bg-[var(--surface)] dark:bg-zinc-900/40" ref={sectionRef}>
      <div className="max-w-screen-xl mx-auto">

        {/* Header */}
        <div
          className="max-w-2xl mx-auto text-center mb-16 transition-all duration-700"
          style={{ opacity: visible ? 1 : 0, transform: visible ? 'none' : 'translateY(24px)' }}
        >
          <p className="text-xs font-semibold text-blue-500 dark:text-blue-400 uppercase tracking-widest mb-3">
            Por qué Vaultly
          </p>
          <h2
            className="text-3xl md:text-4xl font-black text-zinc-900 dark:text-white mb-4"
            style={{ fontFamily: "'Space Grotesk', sans-serif" }}
          >
            ¿Cuántas apps usas ahora mismo?
          </h2>
          <p className="text-zinc-500 dark:text-zinc-400 text-base leading-relaxed">
            Letterboxd para películas. Backloggd para juegos. Goodreads para libros.
            Trakt para series. O una sola app para todo.
          </p>
        </div>

        {/* Before / After comparison */}
        <div
          className="grid grid-cols-1 md:grid-cols-2 gap-4 max-w-2xl mx-auto mb-20 transition-all duration-700 delay-100"
          style={{ opacity: visible ? 1 : 0, transform: visible ? 'none' : 'translateY(24px)' }}
        >
          {/* Before */}
          <div className="rounded-2xl border border-red-500/20 bg-red-500/5 p-6">
            <p className="text-red-400 text-[11px] font-bold uppercase tracking-widest mb-5 flex items-center gap-2">
              <i className="ri-close-circle-line" />
              Sin Vaultly
            </p>
            <div className="flex flex-col gap-3.5">
              {BEFORE.map(item => (
                <div key={item.app} className="flex items-center gap-3">
                  <div
                    className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-lg"
                    style={{ background: `${item.color}15` }}
                  >
                    <i className={`${item.icon} text-sm`} style={{ color: item.color }} />
                  </div>
                  <div>
                    <span className="text-sm font-semibold text-zinc-700 dark:text-zinc-300">{item.app}</span>
                    {item.for && (
                      <span className="ml-1.5 text-xs text-zinc-400 dark:text-zinc-500">para {item.for}</span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* After */}
          <div className="rounded-2xl border border-blue-500/20 bg-blue-500/5 p-6">
            <p className="text-blue-400 text-[11px] font-bold uppercase tracking-widest mb-5 flex items-center gap-2">
              <i className="ri-checkbox-circle-line" />
              Con Vaultly
            </p>
            <div className="flex flex-col gap-3.5">
              {AFTER.map(item => (
                <div key={item.label} className="flex items-center gap-3">
                  <div
                    className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-lg"
                    style={{ background: `${item.color}15` }}
                  >
                    <i className={`${item.icon} text-sm`} style={{ color: item.color }} />
                  </div>
                  <span className="text-sm font-semibold text-zinc-900 dark:text-white">{item.label}</span>
                  <i className="ri-check-line ml-auto text-blue-500 dark:text-blue-400 text-sm" />
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Feature trio */}
        <div
          className="grid grid-cols-1 md:grid-cols-3 gap-6 transition-all duration-700 delay-200"
          style={{ opacity: visible ? 1 : 0, transform: visible ? 'none' : 'translateY(24px)' }}
        >
          {FEATURES.map(f => (
            <div
              key={f.title}
              className="flex items-start gap-4 rounded-2xl border border-[var(--border)] bg-[var(--surface)] p-6"
            >
              <div
                className="flex h-11 w-11 flex-shrink-0 items-center justify-center rounded-xl"
                style={{ background: f.bg }}
              >
                <i className={`${f.icon} text-lg`} style={{ color: f.color }} />
              </div>
              <div>
                <h3 className="mb-1.5 font-bold text-zinc-900 dark:text-white">{f.title}</h3>
                <p className="text-sm leading-relaxed text-zinc-500 dark:text-zinc-400">{f.desc}</p>
              </div>
            </div>
          ))}
        </div>

      </div>
    </section>
  );
}
