import { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { useCategories } from '@/hooks/useCategoryColors';
import { supabase } from '@/lib/supabase';

interface CollectionItem {
  id: string;
  slug: string;
  category: string;
  title: string;
  cover: string;
}

export default function CollectionSection() {
  const CATEGORIES = useCategories();
  const [items, setItems] = useState<CollectionItem[]>([]);
  const [loaded, setLoaded] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold: 0.05 }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  useEffect(() => {
    const load = async () => {
      const { data } = await supabase
        .from('catalog_items')
        .select('id, slug, category, title, image_url')
        .not('image_url', 'is', null)
        .order('updated_at', { ascending: false })
        .limit(24);

      setItems((data ?? []).map(item => ({
        id:       item.id,
        slug:     item.slug,
        category: item.category,
        title:    item.title,
        cover:    item.image_url ?? '',
      })));
      setLoaded(true);
    };
    void load();
  }, []);

  // Fallback gradient placeholders when catalog is empty
  const placeholders = Array.from({ length: 24 }, (_, i) => {
    const cat = CATEGORIES[i % CATEGORIES.length];
    return { id: String(i), cat };
  });

  return (
    <section className="py-24 px-4 md:px-6 bg-zinc-950">
      <div className="mx-auto max-w-screen-xl">

        {/* Section header */}
        <div
          className="mb-10 flex flex-col gap-1 transition-all duration-700 md:flex-row md:items-end md:justify-between"
          style={{ opacity: visible ? 1 : 0, transform: visible ? 'none' : 'translateY(16px)' }}
          ref={ref}
        >
          <div>
            <p className="mb-2 text-[11px] font-bold uppercase tracking-[0.14em] text-blue-400">
              Tu colección
            </p>
            <h2
              className="text-3xl font-black leading-tight tracking-tight text-white md:text-4xl"
              style={{ fontFamily: "'Space Grotesk', sans-serif" }}
            >
              Todo lo que forma parte
              <br className="hidden md:block" /> de tu historia.
            </h2>
          </div>
          <Link
            to="/catalog"
            className="inline-flex cursor-pointer items-center gap-1.5 text-sm font-semibold text-zinc-400 transition-colors hover:text-white"
          >
            Explorar catálogo <i className="ri-arrow-right-line" />
          </Link>
        </div>

        {/* Dense poster grid */}
        <div
          className="grid grid-cols-4 gap-2 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 xl:grid-cols-12 transition-all duration-700"
          style={{
            opacity: visible ? 1 : 0,
            transform: visible ? 'none' : 'translateY(20px)',
            transitionDelay: '100ms',
          }}
        >
          {loaded && items.length > 0
            ? items.map(item => {
                const cat = CATEGORIES.find(c => c.id === item.category);
                return (
                  <Link
                    key={item.id}
                    to={`/catalog/${item.category}/${item.slug}`}
                    className="group relative block aspect-[2/3] cursor-pointer overflow-hidden rounded-lg bg-zinc-900"
                  >
                    <img
                      src={item.cover}
                      alt={item.title}
                      className="h-full w-full object-cover object-top transition-all duration-400 group-hover:scale-105 group-hover:brightness-75"
                      loading="lazy"
                    />
                    {/* Hover overlay */}
                    <div className="absolute inset-0 flex flex-col items-start justify-end bg-gradient-to-t from-black/90 via-black/40 to-transparent p-2 opacity-0 transition-opacity duration-300 group-hover:opacity-100">
                      <p className="line-clamp-2 text-[10px] font-semibold leading-tight text-white">
                        {item.title}
                      </p>
                      {cat && (
                        <span
                          className="mt-1 rounded-full px-1.5 py-0.5 text-[9px] font-bold"
                          style={{ background: `${cat.accent}25`, color: cat.accent }}
                        >
                          {cat.label}
                        </span>
                      )}
                    </div>
                  </Link>
                );
              })
            : placeholders.map(p => (
                <div
                  key={p.id}
                  className={`aspect-[2/3] rounded-lg bg-zinc-900 flex items-center justify-center ${!loaded ? 'animate-pulse' : ''}`}
                >
                  {loaded && (
                    <i
                      className={`${p.cat.icon} text-base opacity-20`}
                      style={{ color: p.cat.accent }}
                    />
                  )}
                </div>
              ))
          }
        </div>

        {/* Sub-caption */}
        <p
          className="mt-6 text-center text-[12px] text-zinc-700 transition-all duration-700"
          style={{
            opacity: visible ? 1 : 0,
            transitionDelay: '250ms',
          }}
        >
          Videojuegos · Películas · Series · Libros · Conciertos
        </p>

      </div>
    </section>
  );
}
